void WitherSkeleton::attackSkill(Player& player) {
	int Damage = (this->AttackPower / 10) * (rand() % 5 - 2) + this->AttackPower;
	battleTextBuffer.push("위더 스켈레톤이 플레이어를 베었다!");
	battleTextBuffer.push("플레이어는 " + std::to_string(player.GetDamage(Damage, 0)) + " 의 피해를 입었다.");
	if (ApplyDebuff(player, WITHER, 3)) {
		battleTextBuffer.push("플레이어는 시듦 상태가 되었다.");
	}
}

