void Creeper::attackSkill(Player& player) {
	if (fuse == 3) {
		battleTextBuffer.push("크리퍼가 치이익 소리를 낸다..");
		fuse--;
	}
	else if (fuse == 2) {
		battleTextBuffer.push("크리퍼에게서 강한 열기가 뿜어져 나온다.");
		fuse--;
	}
	else if (fuse == 1) {
		battleTextBuffer.push("크리퍼가 폭발하기 일보 직전이다!");
		fuse--;
	}
	else {
		battleTextBuffer.push("크리퍼가 굉음을 내며 폭발했다!");
		int creeperDamage = (rand() % 5 - 2) * 10 + this->AttackPower;
		battleTextBuffer.push("플레이어는 " + std::to_string(player.GetDamage(creeperDamage, 0)) + " 의 피해를 입었다.");
		this->Health = 0;
		this->rewardList = {};
	}
}

