void Skeleton::attackSkill(Player& player) {
	int randomValue = rand() % 1000;

	if (randomValue < 700) {
		battleTextBuffer.push("스켈레톤이 플레이어를 뼈다귀로 후려쳤다!");
		int skeletonDamage = (this->AttackPower / 10) * (rand() % 5 - 2) + this->AttackPower;
		battleTextBuffer.push("플레이어는 " + std::to_string(player.GetDamage(skeletonDamage, 0)) + " 의 피해를 입었다.");
		
	}
	else {
		battleTextBuffer.push("스켈레톤이 플레이어에게 삼연발 화살을 쐈다!");
		std::vector<int> skeletonDamage = { 0, 0, 0 };

		for (int i = 0; i < 3; i++) {
			skeletonDamage[i] = this->AttackPower / 3 + (rand() % 3);
		}

		battleTextBuffer.push("플레이어는 각각 " + std::to_string(player.GetDamage(skeletonDamage[0], 0)) + ", " + std::to_string(player.GetDamage(skeletonDamage[1], 0)) + ", " + std::to_string(player.GetDamage(skeletonDamage[2], 0)) + " 의 피해를 입었다.");
	}
}

