void Zombie::attackSkill(Player& player) {
	int randomValue = rand() % 1000;
	
	if (randomValue < 700) {
		battleTextBuffer.push("좀비가 플레이어를 할퀴었다!");
		int zombieDamage = (this->AttackPower / 10) * (rand() % 5 - 2) + this->AttackPower;
		battleTextBuffer.push("플레이어는 " + std::to_string(player.GetDamage(zombieDamage, 0)) + " 의 피해를 입었다.");
		
	}
	else {
		battleTextBuffer.push("좀비가 플레이어를 물었다!");
		int zombieDamage = (this->AttackPower) * 3 / 2;
		battleTextBuffer.push("플레이어는 " + std::to_string(player.GetDamage(zombieDamage, 0)) + " 의 피해를 입었다.");
		
	}
}

