void Ghast::attackSkill(Player& player) {
	int Damage = (this->AttackPower / 10) * (rand() % 5 - 1) + this->AttackPower;
	battleTextBuffer.push("가스트가 플레이어에게 폭발 화염구를 발사했다!");
	battleTextBuffer.push("플레이어는 " + std::to_string(player.GetDamage(Damage, 0)) + " 의 피해를 입었다.");
	
	int RandomValue = rand() % 10;
	if (RandomValue <= 3 && ApplyDebuff(player, FLAME, 3)) {
		battleTextBuffer.push("플레이어의 몸이 불타오르기 시작했다!");
	}
}

