void Blaze::attackSkill(Player& player) {
	if (Charge == 0) {
		Charge = 3;
		battleTextBuffer.push("블레이즈는 불타오르며 화염구를 준비한다..");
	}
	else {
		Charge--;
		int Damage = (this->AttackPower / 10) * (rand() % 5 - 2) + this->AttackPower;
		battleTextBuffer.push("블레이즈가 플레이어에게 화염구를 발사했다!");
		battleTextBuffer.push("플레이어는 " + std::to_string(player.GetDamage(Damage, 0)) + " 의 피해를 입었다.");
		if (ApplyDebuff(player, FLAME, 3)) {
			battleTextBuffer.push("플레이어의 몸이 불타오르기 시작했다!");
		}
	}
}

