void EnderDragon::attackSkill(Player& player) {
	int RandomValue = RandomIntRange(1, 10);

	if (RandomValue <= 6) {
		int Damage = (this->AttackPower / 10) * (rand() % 5 - 2) + this->AttackPower;
		battleTextBuffer.push("엔더 드래곤은 플레이어를 빠른 속도로 덮쳤다!");
		battleTextBuffer.push("플레이어는 " + std::to_string(player.GetDamage(Damage, 0)) + " 의 피해를 입었다.");
		std::system("cls");
		drawBattleScreen(*this);
		int CrystalCount = 1;
		if (RandomIntRange(1, 2) == 1) {
			CrystalCount++;
		}
		Sleep(3000);
		battleTextBuffer.push("플레이어에게 [ 싹트는 수정 ] " + std::to_string(CrystalCount) + " 중첩이 적용되었다.");
		ApplyDebuff(player, BLOOMING_CRYSTAL, CrystalCount);
	}
	else if (RandomValue <= 8 && BreathDuration == -2) {
		int Damage = this->AttackPower * 15 / 10;
		battleTextBuffer.push("엔더 드래곤은 플레이어에게 엔더 브레스를 내뿜었다!");
		battleTextBuffer.push("플레이어는 " + std::to_string(player.GetDamage(Damage, 50)) + " 의 피해를 입었다.");
		BreathDuration = 3;
		std::system("cls");
		drawBattleScreen(*this);
		Sleep(3000);
		int CrystalCount = 1;
		if (RandomIntRange(1, 2) == 1) {
			CrystalCount++;
		}
		battleTextBuffer.push("플레이어에게 [ 싹트는 수정 ] " + std::to_string(CrystalCount) + " 중첩이 적용되었다.");
		ApplyDebuff(player, BLOOMING_CRYSTAL, CrystalCount);
		std::system("cls");
		drawBattleScreen(*this);
		Sleep(3000);
		battleTextBuffer.push("플레이어의 발 아래 브레스의 열기가 작열한다..");
		return;
	}
	else {
		int Heal = 150;
		battleTextBuffer.push("엔더 드래곤은 엔드 수정의 힘으로 체력을 " + std::to_string(this->GetHeal(Heal)) + " 회복했다!");
	}

	if (BreathDuration > -2) {
		if (BreathDuration > 0) {
			std::system("cls");
			drawBattleScreen(*this);
			Sleep(3000);
			int Damage = this->AttackPower / 2;
			battleTextBuffer.push("잔류하는 브레스의 열기가 플레이어를 덮친다!");
			battleTextBuffer.push("플레이어는 " + std::to_string(player.GetDamage(Damage, 50)) + " 의 피해를 입었다.");
			int CrystalCount = 0;
			if (RandomIntRange(1, 2) == 1) {
				CrystalCount++;
			}
			if (CrystalCount > 0) {
				std::system("cls");
				drawBattleScreen(*this);
				Sleep(3000);
				battleTextBuffer.push("플레이어에게 [ 싹트는 수정 ] " + std::to_string(CrystalCount) + " 중첩이 적용되었다.");
			}
		}
		BreathDuration--;
	}
}

