void Enderman::attackSkill(Player& player) {
	if (!isUpset) {
		battleTextBuffer.push("엔더맨이 당신을 응시합니다..");
		return;
	}

	int endermanDamage = (this->AttackPower / 10) * (rand() % 5 - 2) + this->AttackPower;
	battleTextBuffer.push("엔더맨이 플레이어를 강타했다!");
	battleTextBuffer.push("플레이어는 " + std::to_string(player.GetDamage(endermanDamage, 0)) + " 의 피해를 입었다.");
	
}
int Enderman::GetDamage(int Damage, int ArmorPen) {
	int RealDefense = DefensePower * (100 - ArmorPen) / 100;
	int RealDamage = Damage * 100 / (100 + RealDefense);
	RealDamage = RealDamage * (100 + 25 * BuffState[UNSTABLE]) / 100;
	Health -= RealDamage;
	if (!isUpset) {
		isUpset = true;
		battleTextBuffer.push("엔더맨이 분노했습니다!");
	}
	return RealDamage;
}

